const input = JSON.parse($input);
const items = input.items || [];
const subtotal = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
const totalItems = items.reduce((sum, item) => sum + item.quantity, 0);
const bulkDiscount = totalItems >= 50 ? 0.10 : 0;
const discountedSubtotal = subtotal * (1 - bulkDiscount);
const tax = discountedSubtotal * (input.taxRate || 0.08);
const shipping = input.shippingCost || 0;
const total = discountedSubtotal + tax + shipping;
return JSON.stringify({
  subtotal: subtotal.toFixed(2),
  bulkDiscount: bulkDiscount > 0 ? `${(bulkDiscount * 100)}%` : 'none',
  discountedSubtotal: discountedSubtotal.toFixed(2),
  tax: tax.toFixed(2),
  shipping: shipping.toFixed(2),
  total: total.toFixed(2),
  totalItems,
  flagForReview: total > 10000
});

