const error = $input.last().error;
const orderId = $input.first()?.json?.body?.orderId || 'unknown';
return [{
  json: {
    success: false,
    orderId: orderId,
    error: error.message || 'Order processing failed',
    timestamp: new Date().toISOString(),
    retryable: error.httpCode ? error.httpCode >= 500 : true,
    action: 'Please retry or contact support'
  }
}];
